199→// CaptureVoiceNote creates a new voice note item with an S3 audio reference.
200→func (s *Service) CaptureVoiceNote(ctx context.Context, ownerID uuid.UUID, input VoiceNoteInput) (*Item, error) {
201→	if input.AudioKey == "" {
