236→// Update partially updates an item. Only non-nil fields in input are changed.
237→func (s *Service) Update(ctx context.Context, ownerID, itemID uuid.UUID, input UpdateInput) (*Item, error) {
238→	sets := []string{}
239→	args := []any{ownerID, itemID}
240→	paramIdx := 3
241→
