package item

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"

	"github.com/google/uuid"
	"github.com/jackc/pgx/v5"
	"github.com/jackc/pgx/v5/pgxpool"
)

const maxLimit = 100

// itemColumns is the canonical SELECT column list for the items table.
const itemColumns = `id, owner_id, type, status, sensitivity, title, content_text,
	content_url, tags, metadata, auto_metadata, source, source_url,
	created_at, updated_at, captured_at`

// Service provides item CRUD and search operations.
type Service struct {
	pool *pgxpool.Pool
}

// New creates a new item Service.
func New(pool *pgxpool.Pool) *Service {
	return &Service{pool: pool}
}

// GetByID returns a single item by ID and owner. Returns nil, nil if not found.
func (s *Service) GetByID(ctx context.Context, ownerID, itemID uuid.UUID) (*Item, error) {
	query := fmt.Sprintf(`SELECT %s FROM items WHERE owner_id = $1 AND id = $2`, itemColumns)
	row := s.pool.QueryRow(ctx, query, ownerID, itemID)
	it, err := scanItem(row)
	if errors.Is(err, pgx.ErrNoRows) {
		return nil, nil
	}
	if err != nil {
		return nil, fmt.Errorf("item: get by id: %w", err)
	}
	return it, nil
}

// List returns a page of items matching the given filter, sorted and paginated.
func (s *Service) List(ctx context.Context, ownerID uuid.UUID, filter *Filter, limit, offset int, sort *Sort) (*SearchResult, error) {
	limit = clampLimit(limit, maxLimit)
	offset = clampOffset(offset)

	qb := &queryBuilder{}
	qb.add("owner_id = $%d", ownerID)
	applyFilter(qb, filter)
	whereClause := qb.where()

	// Count total
	countQuery := fmt.Sprintf("SELECT COUNT(*) FROM items %s", whereClause)
	var total int
	if err := s.pool.QueryRow(ctx, countQuery, qb.args...).Scan(&total); err != nil {
		return nil, fmt.Errorf("item: list count: %w", err)
	}

	// Determine sort
	orderCol := "created_at"
	orderDir := "DESC"
	if sort != nil {
		if col, ok := sortFieldToColumn(sort.Field); ok {
			orderCol = col
		}
		orderDir = sortDirectionSQL(sort.Direction)
	}

	dataQuery := fmt.Sprintf(`SELECT %s FROM items %s ORDER BY %s %s LIMIT $%d OFFSET $%d`,
		itemColumns, whereClause, orderCol, orderDir, qb.nextParam(), qb.nextParam()+1)
	qb.args = append(qb.args, limit, offset)

	rows, err := s.pool.Query(ctx, dataQuery, qb.args...)
	if err != nil {
		return nil, fmt.Errorf("item: list query: %w", err)
	}
	defer rows.Close()

	items, err := scanItems(rows)
	if err != nil {
		return nil, fmt.Errorf("item: list scan: %w", err)
	}

	return &SearchResult{
		Items:   items,
		Total:   total,
		HasMore: offset+len(items) < total,
	}, nil
}

// Search performs full-text search over items using the search_vector column.
func (s *Service) Search(ctx context.Context, ownerID uuid.UUID, query string, filter *Filter, limit int, threshold float64) (*SearchResult, error) {
	if query == "" {
		return &SearchResult{Items: []*Item{}}, nil
	}
	limit = clampLimit(limit, maxLimit)

	qb := &queryBuilder{}
	qb.add("owner_id = $%d", ownerID)
	qb.add("search_vector @@ plainto_tsquery('english', $%d)", query)
	applyFilter(qb, filter)
	whereClause := qb.where()

	// Count total matches
	countQuery := fmt.Sprintf("SELECT COUNT(*) FROM items %s", whereClause)
	var total int
	if err := s.pool.QueryRow(ctx, countQuery, qb.args...).Scan(&total); err != nil {
		return nil, fmt.Errorf("item: search count: %w", err)
	}

	dataQuery := fmt.Sprintf(
		`SELECT %s FROM items %s ORDER BY ts_rank(search_vector, plainto_tsquery('english', $2)) DESC LIMIT $%d`,
		itemColumns, whereClause, qb.nextParam())
	qb.args = append(qb.args, limit)

	rows, err := s.pool.Query(ctx, dataQuery, qb.args...)
	if err != nil {
		return nil, fmt.Errorf("item: search query: %w", err)
	}
	defer rows.Close()

	items, err := scanItems(rows)
	if err != nil {
		return nil, fmt.Errorf("item: search scan: %w", err)
	}

	return &SearchResult{
		Items:   items,
		Total:   total,
		HasMore: len(items) < total,
	}, nil
}

// CaptureBookmark creates a new bookmark item.
func (s *Service) CaptureBookmark(ctx context.Context, ownerID uuid.UUID, input BookmarkInput) (*Item, error) {
	if input.URL == "" {
		return nil, fmt.Errorf("item: capture bookmark: url is required")
	}
	if input.Source == "" {
		input.Source = "api"
	}
	if input.Sensitivity == "" {
		input.Sensitivity = "normal"
	}

	tags := input.Tags
	if tags == nil {
		tags = []string{}
	}

	query := fmt.Sprintf(`INSERT INTO items (owner_id, type, status, sensitivity, title, content_url, tags, source, metadata, auto_metadata)
		VALUES ($1, 'bookmark', 'pending', $2, $3, $4, $5, $6, '{}', '{}')
		RETURNING %s`, itemColumns)

	row := s.pool.QueryRow(ctx, query,
		ownerID, input.Sensitivity, input.Title, input.URL, tags, input.Source)

	it, err := scanItem(row)
	if err != nil {
		return nil, fmt.Errorf("item: capture bookmark: %w", err)
	}
	return it, nil
}

// CaptureNote creates a new text note item.
func (s *Service) CaptureNote(ctx context.Context, ownerID uuid.UUID, input NoteInput) (*Item, error) {
	if input.Content == "" {
		return nil, fmt.Errorf("item: capture note: content is required")
	}
	if input.Source == "" {
		input.Source = "api"
	}
	if input.Sensitivity == "" {
		input.Sensitivity = "normal"
	}

	tags := input.Tags
	if tags == nil {
		tags = []string{}
	}

	query := fmt.Sprintf(`INSERT INTO items (owner_id, type, status, sensitivity, title, content_text, tags, source, metadata, auto_metadata)
		VALUES ($1, 'text_note', 'ready', $2, $3, $4, $5, $6, '{}', '{}')
		RETURNING %s`, itemColumns)

	row := s.pool.QueryRow(ctx, query,
		ownerID, input.Sensitivity, input.Title, input.Content, tags, input.Source)

	it, err := scanItem(row)
	if err != nil {
		return nil, fmt.Errorf("item: capture note: %w", err)
	}
	return it, nil
}

// CaptureVoiceNote creates a new voice note item with an S3 audio reference.
func (s *Service) CaptureVoiceNote(ctx context.Context, ownerID uuid.UUID, input VoiceNoteInput) (*Item, error) {
	if input.AudioKey == "" {
		return nil, fmt.Errorf("item: capture voice note: audio key is required")
	}
	if input.Source == "" {
		input.Source = "api"
	}
	if input.Sensitivity == "" {
		input.Sensitivity = "normal"
	}

	tags := input.Tags
	if tags == nil {
		tags = []string{}
	}

	metadata := map[string]any{"audio_key": input.AudioKey}
	metadataJSON, err := json.Marshal(metadata)
	if err != nil {
		return nil, fmt.Errorf("item: capture voice note: marshal metadata: %w", err)
	}

	query := fmt.Sprintf(`INSERT INTO items (owner_id, type, status, sensitivity, title, tags, source, metadata, auto_metadata)
		VALUES ($1, 'voice_note', 'pending', $2, $3, $4, $5, $6, '{}')
		RETURNING %s`, itemColumns)

	row := s.pool.QueryRow(ctx, query,
		ownerID, input.Sensitivity, input.Title, tags, input.Source, metadataJSON)

	it, err := scanItem(row)
	if err != nil {
		return nil, fmt.Errorf("item: capture voice note: %w", err)
	}
	return it, nil
}

// Update partially updates an item. Only non-nil fields in input are changed.
func (s *Service) Update(ctx context.Context, ownerID, itemID uuid.UUID, input UpdateInput) (*Item, error) {
	sets := []string{}
	args := []any{ownerID, itemID}
	paramIdx := 3

	if input.Title != nil {
		sets = append(sets, fmt.Sprintf("title = $%d", paramIdx))
		args = append(args, *input.Title)
		paramIdx++
	}
	if input.Tags != nil {
		sets = append(sets, fmt.Sprintf("tags = $%d", paramIdx))
		args = append(args, input.Tags)
		paramIdx++
	}
	if input.Sensitivity != nil {
		sets = append(sets, fmt.Sprintf("sensitivity = $%d", paramIdx))
		args = append(args, *input.Sensitivity)
		paramIdx++ //nolint:ineffassign // keeps pattern consistent for future fields
	}

	if len(sets) == 0 {
		return s.GetByID(ctx, ownerID, itemID)
	}

	query := fmt.Sprintf(`UPDATE items SET %s WHERE owner_id = $1 AND id = $2 RETURNING %s`,
		joinSets(sets), itemColumns)

	row := s.pool.QueryRow(ctx, query, args...)
	it, err := scanItem(row)
	if errors.Is(err, pgx.ErrNoRows) {
		return nil, fmt.Errorf("item: update: not found")
	}
	if err != nil {
		return nil, fmt.Errorf("item: update: %w", err)
	}
	return it, nil
}

// Delete removes an item by ID and owner. Returns an error if not found.
func (s *Service) Delete(ctx context.Context, ownerID, itemID uuid.UUID) error {
	tag, err := s.pool.Exec(ctx,
		"DELETE FROM items WHERE owner_id = $1 AND id = $2",
		ownerID, itemID)
	if err != nil {
		return fmt.Errorf("item: delete: %w", err)
	}
	if tag.RowsAffected() == 0 {
		return fmt.Errorf("item: delete: not found")
	}
	return nil
}

// UpdateSensitivity changes an item's sensitivity level.
func (s *Service) UpdateSensitivity(ctx context.Context, ownerID, itemID uuid.UUID, sensitivity string) (*Item, error) {
	query := fmt.Sprintf(`UPDATE items SET sensitivity = $3 WHERE owner_id = $1 AND id = $2 RETURNING %s`, itemColumns)
	row := s.pool.QueryRow(ctx, query, ownerID, itemID, sensitivity)
	it, err := scanItem(row)
	if errors.Is(err, pgx.ErrNoRows) {
		return nil, fmt.Errorf("item: update sensitivity: not found")
	}
	if err != nil {
		return nil, fmt.Errorf("item: update sensitivity: %w", err)
	}
	return it, nil
}

// Tag replaces an item's tags.
func (s *Service) Tag(ctx context.Context, ownerID, itemID uuid.UUID, tags []string) (*Item, error) {
	if tags == nil {
		tags = []string{}
	}
	query := fmt.Sprintf(`UPDATE items SET tags = $3 WHERE owner_id = $1 AND id = $2 RETURNING %s`, itemColumns)
	row := s.pool.QueryRow(ctx, query, ownerID, itemID, tags)
	it, err := scanItem(row)
	if errors.Is(err, pgx.ErrNoRows) {
		return nil, fmt.Errorf("item: tag: not found")
	}
	if err != nil {
		return nil, fmt.Errorf("item: tag: %w", err)
	}
	return it, nil
}

// ContentUpdate holds fields that background workers set after processing an item.
type ContentUpdate struct {
	Status      string
	Title       *string
	ContentText *string
	ContentURL  *string
}

// UpdateContent updates worker-managed fields (status, title, content) on an item.
// This is used by background jobs, not exposed via GraphQL.
func (s *Service) UpdateContent(ctx context.Context, itemID uuid.UUID, input ContentUpdate) error {
	sets := []string{fmt.Sprintf("status = $%d", 2)}
	args := []any{itemID, input.Status}
	paramIdx := 3

	if input.Title != nil {
		sets = append(sets, fmt.Sprintf("title = $%d", paramIdx))
		args = append(args, *input.Title)
		paramIdx++
	}
	if input.ContentText != nil {
		sets = append(sets, fmt.Sprintf("content_text = $%d", paramIdx))
		args = append(args, *input.ContentText)
		paramIdx++
	}
	if input.ContentURL != nil {
		sets = append(sets, fmt.Sprintf("content_url = $%d", paramIdx))
		args = append(args, *input.ContentURL)
		paramIdx++ //nolint:ineffassign // keeps pattern consistent for future fields
	}

	query := fmt.Sprintf(`UPDATE items SET %s WHERE id = $1`, joinSets(sets))
	tag, err := s.pool.Exec(ctx, query, args...)
	if err != nil {
		return fmt.Errorf("item: update content: %w", err)
	}
	if tag.RowsAffected() == 0 {
		return fmt.Errorf("item: update content: not found")
	}
	return nil
}

func joinSets(sets []string) string {
	result := ""
	for i, s := range sets {
		if i > 0 {
			result += ", "
		}
		result += s
	}
	return result
}

package config

import (
	"fmt"
	"log/slog"
	"os"
	"time"

	"github.com/caarlos0/env/v11"
)

// Config holds all application configuration loaded from environment variables.
type Config struct {
	Host string `env:"HOST" envDefault:"0.0.0.0"`
	Port int    `env:"PORT" envDefault:"8081"`

	DatabaseURL string `env:"DATABASE_URL,required"`
	JWTSecret   string        `env:"JWT_SECRET,required"` //nolint:gosec // config field name, not a hardcoded secret
	JWTExpiry   time.Duration `env:"JWT_EXPIRY" envDefault:"24h"`

	S3Endpoint       string `env:"S3_ENDPOINT"`
	S3Bucket         string `env:"S3_BUCKET" envDefault:"flotsam-dev"`
	S3AccessKey      string `env:"S3_ACCESS_KEY"`
	S3SecretKey      string `env:"S3_SECRET_KEY"`
	S3Region         string `env:"S3_REGION" envDefault:"us-east-1"`
	S3ForcePathStyle bool   `env:"S3_FORCE_PATH_STYLE" envDefault:"false"`

	OpenAIAPIKey string `env:"OPENAI_API_KEY"`
	OllamaURL    string `env:"OLLAMA_URL"`

	WhisperModel      string `env:"WHISPER_MODEL" envDefault:"whisper-1"`
	WhisperLocalBin   string `env:"WHISPER_LOCAL_BIN"`
	WhisperLocalModel string `env:"WHISPER_LOCAL_MODEL"`
	MaxUploadSize     int64  `env:"MAX_UPLOAD_SIZE" envDefault:"52428800"` // 50MB

	LogLevel  string `env:"LOG_LEVEL" envDefault:"info"`
	LogFormat string `env:"LOG_FORMAT" envDefault:"json"`

	Env string `env:"ENV" envDefault:"development"`

	CORSOrigins string `env:"CORS_ORIGINS"`

	GQLPlayground    bool `env:"GRAPHQL_PLAYGROUND" envDefault:"false"`
	GQLIntrospection bool `env:"GRAPHQL_INTROSPECTION" envDefault:"false"`

	MCPEnabled bool `env:"MCP_ENABLED" envDefault:"true"`

	RateLimitEnabled     bool `env:"RATE_LIMIT_ENABLED" envDefault:"true"`
	RateLimitGraphQL     int  `env:"RATE_LIMIT_GRAPHQL" envDefault:"60"`
	RateLimitGraphQLAuth int  `env:"RATE_LIMIT_GRAPHQL_AUTH" envDefault:"120"`
	RateLimitMCP         int  `env:"RATE_LIMIT_MCP" envDefault:"120"`

	ShutdownTimeout time.Duration `env:"SHUTDOWN_TIMEOUT" envDefault:"15s"`
}

// Load parses and validates configuration from environment variables.
func Load() (*Config, error) {
	cfg := &Config{}
	if err := env.Parse(cfg); err != nil {
		return nil, fmt.Errorf("config: %w", err)
	}
	return cfg, nil
}

// Addr returns the host:port bind address.
func (c *Config) Addr() string {
	return fmt.Sprintf("%s:%d", c.Host, c.Port)
}

// ParseLogLevel converts a log level string to the corresponding slog.Level.
func ParseLogLevel(s string) slog.Level {
	switch s {
	case "trace":
		return slog.Level(-8) // custom TRACE level
	case "debug":
		return slog.LevelDebug
	case "warn":
		return slog.LevelWarn
	case "error":
		return slog.LevelError
	default:
		return slog.LevelInfo
	}
}

// LogHandler returns an slog.Handler configured per LOG_LEVEL and LOG_FORMAT.
func (c *Config) LogHandler() slog.Handler {
	level := ParseLogLevel(c.LogLevel)
	opts := &slog.HandlerOptions{
		Level:     level,
		AddSource: c.Env == "development",
	}

	if c.LogFormat == "text" {
		return slog.NewTextHandler(os.Stderr, opts)
	}
	return slog.NewJSONHandler(os.Stderr, opts)
}

package worker

import (
	"context"
	"encoding/json"
	"fmt"
	"log/slog"
	"path/filepath"
	"strings"

	"github.com/google/uuid"
	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/riverqueue/river"

	"github.com/ketang/flotsam/api/internal/provider"
	"github.com/ketang/flotsam/api/internal/storage"
)

// TranscribeArgs are the arguments for a transcription job.
type TranscribeArgs struct {
	ItemID   uuid.UUID `json:"item_id"`
	OwnerID  uuid.UUID `json:"owner_id"`
	AudioKey string    `json:"audio_key"`
}

func (TranscribeArgs) Kind() string { return "transcribe" }

// TranscribeWorker transcribes audio via Whisper API or local whisper.cpp.
type TranscribeWorker struct {
	river.WorkerDefaults[TranscribeArgs]
	Storage     *storage.Client
	Transcriber provider.Transcriber
	Pool        *pgxpool.Pool
}

func (w *TranscribeWorker) Work(ctx context.Context, job *river.Job[TranscribeArgs]) error {
	slog.InfoContext(ctx, "worker: transcribe: processing",
		"item_id", job.Args.ItemID,
		"audio_key", job.Args.AudioKey,
	)

	if w.Storage == nil {
		return fmt.Errorf("worker: transcribe: storage not configured")
	}
	if w.Transcriber == nil {
		return fmt.Errorf("worker: transcribe: transcriber not configured")
	}

	// Update item status to processing
	if err := w.updateStatus(ctx, job.Args.ItemID, job.Args.OwnerID, "processing", nil); err != nil {
		return fmt.Errorf("worker: transcribe: set processing: %w", err)
	}

	// Download audio from S3
	reader, err := w.Storage.Download(ctx, job.Args.AudioKey)
	if err != nil {
		w.setError(ctx, job.Args.ItemID, job.Args.OwnerID, "failed to download audio")
		return fmt.Errorf("worker: transcribe: download audio: %w", err)
	}
	defer func() { _ = reader.Close() }()

	// Determine format from key extension
	ext := strings.TrimPrefix(filepath.Ext(job.Args.AudioKey), ".")
	if ext == "" {
		ext = "wav"
	}

	// Transcribe
	transcript, err := w.Transcriber.Transcribe(ctx, reader, provider.TranscribeOpts{
		Format: ext,
	})
	if err != nil {
		w.setError(ctx, job.Args.ItemID, job.Args.OwnerID, "transcription failed")
		return fmt.Errorf("worker: transcribe: transcribe: %w", err)
	}

	// Update item with transcript
	_, err = w.Pool.Exec(ctx,
		`UPDATE items SET content_text = $1, status = 'ready', updated_at = now()
		 WHERE id = $2 AND owner_id = $3`,
		transcript, job.Args.ItemID, job.Args.OwnerID)
	if err != nil {
		return fmt.Errorf("worker: transcribe: update item: %w", err)
	}

	slog.InfoContext(ctx, "worker: transcribe: completed",
		"item_id", job.Args.ItemID,
		"transcript_len", len(transcript),
	)
	return nil
}

// updateStatus sets the item's status and optionally stores an error in metadata.
func (w *TranscribeWorker) updateStatus(ctx context.Context, itemID, ownerID uuid.UUID, status string, errMsg *string) error {
	if errMsg != nil {
		meta := map[string]any{"error": *errMsg}
		metaJSON, err := json.Marshal(meta)
		if err != nil {
			return fmt.Errorf("worker: transcribe: marshal error metadata: %w", err)
		}
		_, err = w.Pool.Exec(ctx,
			`UPDATE items SET status = $1, metadata = metadata || $4::jsonb, updated_at = now()
			 WHERE id = $2 AND owner_id = $3`,
			status, itemID, ownerID, metaJSON)
		return err
	}
	_, err := w.Pool.Exec(ctx,
		`UPDATE items SET status = $1, updated_at = now() WHERE id = $2 AND owner_id = $3`,
		status, itemID, ownerID)
	return err
}

// setError is a convenience method that sets the item status to "error".
func (w *TranscribeWorker) setError(ctx context.Context, itemID, ownerID uuid.UUID, msg string) {
	if err := w.updateStatus(ctx, itemID, ownerID, "error", &msg); err != nil {
		slog.ErrorContext(ctx, "worker: transcribe: failed to set error status",
			"item_id", itemID,
			"error", err,
		)
	}
}

package item

import (
	"time"

	"github.com/google/uuid"
)

// Item represents an item stored in the database.
type Item struct {
	ID           uuid.UUID
	OwnerID      uuid.UUID
	Type         string
	Status       string
	Sensitivity  string
	Title        *string
	ContentText  *string
	ContentURL   *string
	Tags         []string
	Metadata     map[string]any
	AutoMetadata map[string]any
	Source       string
	SourceURL    *string
	CreatedAt    time.Time
	UpdatedAt    time.Time
	CapturedAt   time.Time
