		target:    server.URL,
		transport: server.Client().Transport,
	}

	_, err := embedder.Embed(context.Background(), "hello")
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if receivedModel != "text-embedding-3-large" {
		t.Errorf("expected model 'text-embedding-3-large', got %q", receivedModel)
	}
}

// urlRewriter is an http.RoundTripper that redirects all requests to a target URL.
type urlRewriter struct {
	target    string
	transport http.RoundTripper
}

func (u *urlRewriter) RoundTrip(req *http.Request) (*http.Response, error) {
	req = req.Clone(req.Context())
	req.URL.Scheme = "http"
	req.URL.Host = strings.TrimPrefix(u.target, "http://")
	transport := u.transport
	if transport == nil {
		transport = http.DefaultTransport
	}
	return transport.RoundTrip(req)
}

