package worker

import (
	"context"
	"fmt"
	"log/slog"
	"net/http"
	"strings"
	"time"

	readability "github.com/go-shiori/go-readability"
	"github.com/google/uuid"
	"github.com/riverqueue/river"

	"github.com/ketang/flotsam/api/internal/item"
	"github.com/ketang/flotsam/api/internal/storage"
)

// ItemContentUpdater updates worker-managed fields on items.
type ItemContentUpdater interface {
	UpdateContent(ctx context.Context, itemID uuid.UUID, input item.ContentUpdate) error
}

const (
	fetchTimeout = 30 * time.Second
	userAgent    = "Flotsam/1.0 (bookmark fetcher)"
)

// PageFetchArgs are the arguments for a page fetch job.
type PageFetchArgs struct {
	ItemID uuid.UUID `json:"item_id"`
	URL    string    `json:"url"`
}

func (PageFetchArgs) Kind() string { return "page_fetch" }

// PageFetchWorker fetches and extracts readable content from bookmark URLs.
type PageFetchWorker struct {
	river.WorkerDefaults[PageFetchArgs]
	Items   ItemContentUpdater
	Storage *storage.Client // nil if S3 not configured
	Client  *http.Client    // nil uses a default client with timeout
}

func (w *PageFetchWorker) httpClient() *http.Client {
	if w.Client != nil {
		return w.Client
	}
	return &http.Client{Timeout: fetchTimeout}
}

func (w *PageFetchWorker) Work(ctx context.Context, job *river.Job[PageFetchArgs]) error {
	itemID := job.Args.ItemID
	url := job.Args.URL

	slog.InfoContext(ctx, "worker: page_fetch: processing",
		"item_id", itemID,
		"url", url,
	)

	// Mark item as processing
	if err := w.Items.UpdateContent(ctx, itemID, item.ContentUpdate{Status: "processing"}); err != nil {
		return fmt.Errorf("worker: page_fetch: set processing: %w", err)
	}

	// Fetch and extract content
	article, err := w.fetchAndExtract(ctx, url)
	if err != nil {
		// Set item to error status
		_ = w.Items.UpdateContent(ctx, itemID, item.ContentUpdate{Status: "error"})
		return fmt.Errorf("worker: page_fetch: fetch: %w", err)
	}

	// Upload HTML to S3 if storage is configured
	var contentURL *string
	if w.Storage != nil && article.Content != "" {
		key := fmt.Sprintf("items/%s/page.html", itemID)
		if err := w.Storage.Upload(ctx, key, strings.NewReader(article.Content), "text/html"); err != nil {
			slog.ErrorContext(ctx, "worker: page_fetch: s3 upload failed, continuing without",
				"item_id", itemID,
				"error", err,
			)
		} else {
			contentURL = &key
		}
	}

	// Build content update
	update := item.ContentUpdate{Status: "ready"}
	if article.Title != "" {
		update.Title = &article.Title
	}
	if article.TextContent != "" {
		update.ContentText = &article.TextContent
	}
	if contentURL != nil {
		update.ContentURL = contentURL
	}

	if err := w.Items.UpdateContent(ctx, itemID, update); err != nil {
		return fmt.Errorf("worker: page_fetch: update item: %w", err)
	}

	slog.InfoContext(ctx, "worker: page_fetch: done",
		"item_id", itemID,
		"title", article.Title,
		"text_length", len(article.TextContent),
	)
	return nil
}

type fetchResult struct {
	Title       string
	TextContent string
	Content     string // HTML content
}

func (w *PageFetchWorker) fetchAndExtract(ctx context.Context, url string) (*fetchResult, error) {
	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
	if err != nil {
		return nil, fmt.Errorf("build request: %w", err)
	}
	req.Header.Set("User-Agent", userAgent)

	resp, err := w.httpClient().Do(req)
	if err != nil {
		return nil, fmt.Errorf("http get: %w", err)
	}
	defer func() { _ = resp.Body.Close() }()

	if resp.StatusCode >= 400 {
		return nil, fmt.Errorf("http status %d for %s", resp.StatusCode, url)
	}

	article, err := readability.FromReader(resp.Body, nil)
	if err != nil {
		return nil, fmt.Errorf("readability parse: %w", err)
	}

	return &fetchResult{
		Title:       article.Title,
		TextContent: article.TextContent,
		Content:     article.Content,
	}, nil
}

