// SemanticSearch finds items similar to the given embedding vector using cosine similarity.
func (s *Service) SemanticSearch(ctx context.Context, ownerID uuid.UUID, embedding []float32, filter *Filter, limit int, threshold float64) (*SearchResult, error) {
	if len(embedding) == 0 {
		return &SearchResult{Items: []*Item{}}, nil
	}
	limit = clampLimit(limit, maxLimit)

	vec := pgvector.NewVector(embedding)

	qb := &queryBuilder{}
	qb.add("owner_id = $%d", ownerID)
	qb.add("embedding IS NOT NULL", nil)
	applyFilter(qb, filter)

	// Override the "embedding IS NOT NULL" condition — queryBuilder doesn't support
	// no-arg conditions directly, so we handle it by not using the placeholder.
	// Re-do this properly:
	qb2 := &queryBuilder{}
	qb2.add("owner_id = $%d", ownerID)
	applyFilter(qb2, filter)

	// Add the embedding vector as a parameter for the cosine distance operator
	embeddingParam := qb2.nextParam()
	qb2.args = append(qb2.args, vec)

	// Add threshold filter: cosine similarity = 1 - cosine distance
	thresholdParam := qb2.nextParam()
	qb2.args = append(qb2.args, threshold)

	whereClause := qb2.where()
	// Append embedding conditions to WHERE
	if whereClause == "" {
		whereClause = fmt.Sprintf("WHERE embedding IS NOT NULL AND (1 - (embedding <=> $%d)) >= $%d", embeddingParam, thresholdParam)
	} else {
		whereClause += fmt.Sprintf(" AND embedding IS NOT NULL AND (1 - (embedding <=> $%d)) >= $%d", embeddingParam, thresholdParam)
	}

	// Count total matches
	countQuery := fmt.Sprintf("SELECT COUNT(*) FROM items %s", whereClause)
	var total int
	if err := s.pool.QueryRow(ctx, countQuery, qb2.args...).Scan(&total); err != nil {
		return nil, fmt.Errorf("item: semantic search count: %w", err)
	}

	limitParam := len(qb2.args) + 1
	qb2.args = append(qb2.args, limit)

	dataQuery := fmt.Sprintf(
		`SELECT %s FROM items %s ORDER BY embedding <=> $%d LIMIT $%d`,
		itemColumns, whereClause, embeddingParam, limitParam)

	rows, err := s.pool.Query(ctx, dataQuery, qb2.args...)
	if err != nil {
		return nil, fmt.Errorf("item: semantic search query: %w", err)
	}
	defer rows.Close()

	items, err := scanItems(rows)
	if err != nil {
		return nil, fmt.Errorf("item: semantic search scan: %w", err)
	}

	return &SearchResult{
		Items:   items,
		Total:   total,
		HasMore: len(items) < total,
	}, nil
}

