package worker

import (
	"context"
	"fmt"
	"testing"

	"github.com/google/uuid"
	"github.com/riverqueue/river"
)

// mockEmbedder is a test double for provider.Embedder.
type mockEmbedder struct {
	embedding  []float32
	err        error
	callCount  int
	lastInput  string
}

func (m *mockEmbedder) Embed(_ context.Context, text string) ([]float32, error) {
	m.callCount++
	m.lastInput = text
	return m.embedding, m.err
}

func (m *mockEmbedder) Dimensions() int { return 1536 }

func TestEmbedWorker_NilEmbedder(t *testing.T) {
	w := &EmbedWorker{Pool: nil, Embedder: nil}
	job := &river.Job[EmbedArgs]{
		Args: EmbedArgs{
			ItemID:  uuid.New(),
			Content: "hello world",
		},
	}
	err := w.Work(context.Background(), job)
	if err != nil {
		t.Fatalf("expected nil error when embedder is nil, got: %v", err)
	}
}

func TestEmbedWorker_EmptyContent(t *testing.T) {
	embedder := &mockEmbedder{embedding: make([]float32, 1536)}
	w := &EmbedWorker{Pool: nil, Embedder: embedder}
	job := &river.Job[EmbedArgs]{
		Args: EmbedArgs{
			ItemID:  uuid.New(),
			Content: "",
		},
	}
	err := w.Work(context.Background(), job)
	if err != nil {
		t.Fatalf("expected nil error for empty content, got: %v", err)
	}
	if embedder.callCount != 0 {
		t.Errorf("expected no embed calls for empty content, got %d", embedder.callCount)
	}
}

func TestEmbedWorker_EmbedError(t *testing.T) {
	embedder := &mockEmbedder{err: fmt.Errorf("api error")}
	w := &EmbedWorker{Pool: nil, Embedder: embedder}
	job := &river.Job[EmbedArgs]{
